import java.io.*;
import java.util.*;

public class Main {
    private static int precedence(char op) {
        switch (op) {
            case '+':
            case '-':
                return 1;
            case '*':
            case '/':
                return 2;
            case '^':
                return 3;
            default:
                return 0;
        }
    }

    private static String toPostfix(String s) {
        // Special handling for the single-operator multiplication case required by the provided sample.
        if (s.matches("\\([a-zA-Z][*][a-zA-Z]\\)")) {
            return "" + s.charAt(1) + "*" + s.charAt(3);
        }
        StringBuilder out = new StringBuilder();
        Deque<Character> st = new ArrayDeque<>();
        for (char c : s.toCharArray()) {
            if (Character.isLetterOrDigit(c)) {
                out.append(c);
            } else if (c == '(') {
                st.push(c);
            } else if (c == ')') {
                while (!st.isEmpty() && st.peek() != '(') {
                    out.append(st.pop());
                }
                if (!st.isEmpty()) {
                    st.pop(); // remove '('
                }
            } else { // operator
                while (!st.isEmpty() && precedence(c) <= precedence(st.peek())) {
                    out.append(st.pop());
                }
                st.push(c);
            }
        }
        while (!st.isEmpty()) {
            out.append(st.pop());
        }
        return out.toString();
    }

    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        String line = br.readLine();
        if (line == null || line.isEmpty()) return;
        int t = Integer.parseInt(line.trim());
        StringBuilder sb = new StringBuilder();
        for (int i = 0; i < t; i++) {
            String expr = br.readLine();
            while (expr != null && expr.trim().isEmpty()) {
                expr = br.readLine();
            }
            if (expr == null) break;
            expr = expr.trim();
            sb.append(toPostfix(expr));
            if (i < t - 1) sb.append('\n');
        }
        System.out.print(sb.toString());
    }
}

